import sqlite3
import re
from flask import Flask, request, render_template, redirect, url_for, session, jsonify

app = Flask(__name__)
app.secret_key = 'vanguardia_secret_session_key_!99'
DB_PATH = '/tmp/vanguardia_logistics.db'

def get_db_connection():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def security_shield(payload):
    if not payload:
        return True
    # Realistic WAF: Blocks common keywords followed by whitespace and literal spaces
    # Also blocks common comment markers
    blocked_patterns = [r"\s", r"UNION\b", r"SELECT\b", r"WHERE\b", r"OR\b", r"AND\b", r"--", r"/\*", r"#"]
    for pattern in blocked_patterns:
        if re.search(pattern, payload, re.IGNORECASE):
            return False
    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        if username == 'coordinator' and password == 'vanguardia2024':
            session['user'] = 'coordinator'
            return redirect(url_for('dashboard'))
        return render_template('login.html', error='Invalid credentials')
    return render_template('login.html')

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    return render_template('dashboard.html')

@app.route('/shipments')
def shipments():
    if 'user' not in session:
        return redirect(url_for('login'))

    order = request.args.get('order', 'id')

    if not security_shield(order):
        return "Security Shield: Malicious activity detected!", 403

    conn = get_db_connection()
    try:
        # Vulnerable ORDER BY injection point
        query = f"SELECT id, tracking_no, status, origin, destination FROM shipments ORDER BY {order}"
        shipments = conn.execute(query).fetchall()
    except Exception as e:
        return f"Database Error: {str(e)}", 500
    finally:
        conn.close()

    return render_template('shipments.html', shipments=shipments, current_order=order)

@app.route('/carriers')
def carriers():
    if 'user' not in session:
        return redirect(url_for('login'))
    search = request.args.get('search', '')
    conn = get_db_connection()
    # Safely handled search for comparison
    carriers = conn.execute("SELECT * FROM carriers WHERE name LIKE ?", ('%' + search + '%',)).fetchall()
    conn.close()
    return render_template('carriers.html', carriers=carriers)

@app.route('/api/v1/shipment/<int:shipment_id>')
def api_shipment(shipment_id):
    conn = get_db_connection()
    shipment = conn.execute("SELECT * FROM shipments WHERE id = ?", (shipment_id,)).fetchone()
    conn.close()
    if shipment:
        return jsonify(dict(shipment))
    return jsonify({"error": "Not found"}), 404

@app.route('/profile')
def profile():
    if 'user' not in session:
        return redirect(url_for('login'))
    return render_template('profile.html', user={'name': 'System Coordinator', 'role': 'Admin', 'region': 'Global'})

@app.route('/help')
def help():
    return render_template('help.html')

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)
